namespace sv_426c73bb10224ab2907f94a0abe3f34d.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public class ThemeService
{
    private Theme _theme = Theme.Light;
    private string _accentColor = "#0d6efd";

    public Theme CurrentTheme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChange;

    private void NotifyChanged() => OnChange?.Invoke();
}

@* This component MUST have its own rendermode so it can re-render
   when the scoped ThemeService fires OnChange. Static SSR components
   cannot re-render after the initial response. *@
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<span class="theme-indicator badge rounded-pill @BadgeClass">
    @Icon @ThemeService.CurrentTheme
</span>

@code {
    private string BadgeClass => ThemeService.CurrentTheme switch
    {
        Theme.Dark => "text-bg-dark",
        Theme.System => "text-bg-secondary",
        _ => "text-bg-light text-dark border"
    };

    private string Icon => ThemeService.CurrentTheme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    protected override void OnInitialized()
    {
        ThemeService.OnChange += OnThemeChanged;
    }

    private void OnThemeChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        ThemeService.OnChange -= OnThemeChanged;
    }
}

@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<div class="theme-toggle d-inline-flex align-items-center gap-2">
    <button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
            title="Current: @ThemeService.CurrentTheme">
        @Icon Switch Theme
    </button>
    <span class="small text-muted">@ThemeService.CurrentTheme</span>
</div>

@code {
    private string Icon => ThemeService.CurrentTheme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    private void CycleTheme()
    {
        ThemeService.CurrentTheme = ThemeService.CurrentTheme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += OnThemeChanged;
    }

    private void OnThemeChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        ThemeService.OnChange -= OnThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>
        <div class="btn-group mb-3" role="group">
            @foreach (var theme in Enum.GetValues<Theme>())
            {
                <button class="btn @(ThemeService.CurrentTheme == theme ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => ThemeService.CurrentTheme = theme">
                    @theme
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>
        <div class="d-flex align-items-center gap-3 mb-3">
            <input type="color"
                   class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="OnAccentChanged"
                   title="Choose accent color" />
            <span class="font-monospace small">@ThemeService.AccentColor</span>
        </div>

        <div class="alert alert-info mt-3 small">
            Changes apply immediately to all components,
            including the header theme indicator.
        </div>
    </div>
</div>

@code {
    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += OnThemeChanged;
    }

    private void OnThemeChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        ThemeService.OnChange -= OnThemeChanged;
    }
}

